882	async function loadStore(q) {
883	  // 드릴다운 진행 중이면 그 퍼블리셔의 목록만 다시 그린다(카드 그리드는 갱신만).
884	  // 새로고침 후 actualSkillCount가 바뀔 수 있으므로 storePublisher 참조도 최신화한다.
885	  if (storePublisher) {
886	    const slug = storePublisher.slug;
887	    await loadPublishers();
888	    const fresh = (storePublishers || []).find((p) => p.slug === slug);
889	    if (fresh) {
890	      storePublisher = fresh;
891	      const f = fresh.actualSkillCount != null;
892	      $('#store-drill-sub').textContent = f
893	        ? `${fresh.actualSkillCount} skills · ${fresh.repoCount || 0} repos`
894	        : `~${fresh.totalSkillsCurated || 0} skills 예상 · ${fresh.repoCount || 0} repos`;
895	    }
896	    await loadPublisherSkills();
897	    return;
898	  }
899	
900	  showLoading('#store-list');
901	  let d, regs;
902	  try {
903	    [d, regs] = await Promise.all([
904	      api('/store' + (q ? '?q=' + encodeURIComponent(q) : '')),
905	      api('/registries').catch(() => ({ registries: [] })),
906	    ]);
907	  } catch { showLoadError('#store-list', () => loadStore(q)); return; }
908	  lastRegistries = regs.registries || [];
909	  setCount('store', (d.items || []).length);
910	  await loadPublishers();
911	
912	  // 번들·검색 결과(기존 카드) — 기존 canonical 태그 필터(activeTag) 적용, 흐름 불변.
913	  const items = (d.items || []).filter(tagMatch);
914	  const list = $('#store-list');
915	  // #5: 스토어 빈 상태 분기 — 필터/검색이 있으면 [필터 해제], 없으면 [레지스트리]에서 새로고침 안내.
916	  const hasFilter = !!activeTag || !!(q && q.trim());
917	  const emptyHtml = hasFilter
918	    ? `<div class="empty-state">검색/필터 결과 없음<span class="inline-acts" style="justify-content:center;margin-top:10px"><button class="btn btn-secondary btn-sm" data-store-clear-filter="1">필터 해제</button></span></div>`
919	    : `<div class="empty-state">번들/등록된 항목이 없습니다<span class="inline-acts" style="justify-content:center;margin-top:10px"><button class="btn btn-secondary btn-sm" data-reg-open="1">📚 레지스트리에서 새로고침</button></span></div>`;
920	  list.innerHTML = items.length ? items.map(storeCardHtml).join('') : emptyHtml;
921	}
922	
923	// ── SKC2: 퍼블리셔 카드 그리드 ────────────────────────────────────────
924	async function loadPublishers() {
925	  const grid = $('#store-pub-grid');
926	  if (!grid) return;
927	  let d;
928	  try { d = await api('/publishers'); }
929	  catch { showLoadError('#store-pub-grid', loadPublishers); return; }
930	  storePublishers = d.publishers || [];
931	  // 'user'(사용자 추가) 그룹은 항목(repo)이 있을 때만 노출.
932	  const shown = storePublishers.filter((p) => p.slug !== 'user' || (p.repoCount || 0) > 0);
933	  grid.innerHTML = shown.length ? shown.map((p) => {
934	    const fetched = p.actualSkillCount != null;
935	    // N = 실제값(fetched) 또는 예상(totalSkillsCurated, 은은한 톤).
936	    const n = fetched ? p.actualSkillCount : (p.totalSkillsCurated || 0);
937	    const skillsChip = fetched
938	      ? `<span class="pub-num">${n}</span> skills`
939	      : `<span class="pub-num est">~${n}</span> <span class="pub-est-note">skills 예상</span>`;
940	    const state = fetched
941	      ? `<span class="pub-state ready">✓ 목록 가져옴 · 클릭해서 적용</span>`
942	      : `<span class="pub-state needs-fetch">↻ 아직 미수집 · 클릭 후 저장소 새로고침</span>`;
943	    return `<button class="pub-card" data-pub-open="${esc(p.slug)}">
944	      <span class="pub-ic">🏪</span>
945	      <span class="pub-body">
946	        <span class="pub-name">${esc(p.name)}${p.official ? '' : ' <span class="badge muted">사용자</span>'}</span>
947	        <span class="pub-meta">${skillsChip} · <span class="pub-num">${p.repoCount || 0}</span> repos</span>
948	        ${state}
949	      </span>
950	    </button>`;
951	  }).join('') : '<div class="empty-state">퍼블리셔 없음.</div>';
952	}
