954	// 카드 클릭 → 드릴다운 진입.
955	function openPublisherDrilldown(slug) {
956	  const pub = (storePublishers || []).find((p) => p.slug === slug);
957	  if (!pub) return;
958	  storePublisher = pub;
959	  storeCatTag = null;
960	  $('#store-default').hidden = true;
961	  $('#store-drilldown').hidden = false;
962	  $('#store-drill-title').textContent = pub.name;
963	  const fetched = pub.actualSkillCount != null;
964	  $('#store-drill-sub').textContent = fetched
965	    ? `${pub.actualSkillCount} skills · ${pub.repoCount || 0} repos`
966	    : `~${pub.totalSkillsCurated || 0} skills 예상 · ${pub.repoCount || 0} repos`;
967	  renderCategoryChips();
968	  loadPublisherSkills();
969	}
