971	// [← 전체] — 카드 그리드로 복귀.
972	function closePublisherDrilldown() {
973	  storePublisher = null;
974	  storeCatTag = null;
975	  $('#store-drilldown').hidden = true;
976	  $('#store-default').hidden = false;
977	  loadStore($('#global-search-input') ? $('#global-search-input').value : '');
978	}
