980	// 카테고리 필터 칩(skill-tags 10종) — 기존 filter-pill 패턴 재사용, data-pub-cat 분기.
981	function renderCategoryChips() {
982	  const box = $('#store-cat-filters');
983	  if (!box) return;
984	  box.innerHTML =
985	    `<button class="filter-pill ${storeCatTag === null ? 'active' : ''}" data-pub-cat="">전체</button>` +
986	    CATEGORY_TAGS.map((t) => `<button class="filter-pill ${storeCatTag === t.key ? 'active' : ''}" data-pub-cat="${esc(t.key)}">${esc(t.ko)}</button>`).join('');
987	}
988	
989	function applyCategoryFilter(key) {
990	  storeCatTag = (key === '' || key === storeCatTag) ? null : key;
991	  renderCategoryChips();
992	  loadPublisherSkills();
993	}
