995	// 드릴다운 스킬 목록: GET /store?publisher=<slug> + 클라이언트 카테고리 필터.
996	async function loadPublisherSkills() {
997	  if (!storePublisher) return;
998	  const list = $('#store-drill-list');
999	  const pub = storePublisher;
1000	  const fetched = pub.actualSkillCount != null;
1001	
1002	  // 미fetch 상태: 아직 가져오지 않음 — 해당 퍼블리셔 repo들의 [새로고침] 유도.
1003	  if (!fetched) {
1004	    const refreshBtns = (pub.repos || []).map((r) =>
1005	      `<button class="btn btn-secondary btn-sm" data-reg-refresh="${esc(r.id)}">↻ ${esc(r.name || r.id)}</button>`
1006	    ).join('');
1007	    list.innerHTML = `<div class="pub-empty-fetch">
1008	      <div class="pef-title">아직 로컬에 가져온 목록이 없습니다</div>
1009	      <div class="pef-sub">아래 저장소를 새로고침하면 스킬 목록을 로컬 캐시에 불러옵니다. 실제 적용은 다음 단계에서 다시 미리보기합니다. (예상 ~${pub.totalSkillsCurated || 0}개)</div>
1010	      <div class="pef-acts">${refreshBtns || '<span class="muted">저장소 없음</span>'}</div>
1011	    </div>`;
1012	    return;
1013	  }
1014	
1015	  showLoading('#store-drill-list');
1016	  let d;
1017	  try { d = await api('/store?publisher=' + encodeURIComponent(pub.slug)); }
1018	  catch { showLoadError('#store-drill-list', loadPublisherSkills); return; }
1019	  let items = d.items || [];
1020	  if (storeCatTag) items = items.filter((it) => (it.tags || []).includes(storeCatTag));
1021	  list.innerHTML = items.length
1022	    ? items.map(storeCardHtml).join('')
1023	    : `<div class="empty-state">${storeCatTag ? '이 카테고리에 해당하는 스킬이 없습니다.' : '스킬 없음.'}</div>`;
1024	}
