1026	async function openStoreDetail(id) {
1027	  let item, prev;
1028	  try {
1029	    [item, prev] = await Promise.all([
1030	      api('/store/item?id=' + encodeURIComponent(id)),
1031	      api('/store/preview?id=' + encodeURIComponent(id)),
1032	    ]);
1033	  } catch (e) { toast('미리보기를 불러오지 못했습니다: ' + e.message); return; }
1034	  const allLosses = [];
1035	  let bodyHead = '';
1036	  if (item && item.kind === 'skill' && item.body) bodyHead = `<div class="sub-label">본문</div><div class="code-block">${esc(item.body)}</div>`;
1037	  else if (item && item.kind === 'agent' && item.neutral) bodyHead = `<div class="sub-label">중립 스키마</div><div class="code-block">${esc(JSON.stringify(item.neutral, null, 2))}</div>`;
1038	
1039	  const perTool = (prev.perTool || []).map((pt) => {
1040	    (pt.losses || []).forEach((l) => allLosses.push(`[${pt.to}] ${l}`));
1041	    return `<div class="ov-card">
1042	      <div class="ov-head"><span class="tool-dot" style="background:${TOOL_COLOR[pt.to]}"></span>${esc(pt.to)}</div>
1043	      <div class="ov-kv"><b>대상</b> <code>${esc((pt.targetPath || '').split('/').slice(-2).join('/'))}</code></div>
1044	      <div class="code-block" style="max-height:150px;font-size:11.5px">${esc(pt.diffText || '(차이 없음)')}</div>
1045	    </div>`;
1046	  }).join('');
1047	
1048	  openPanel({
1049	    title: (item && item.name) || id,
1050	    meta: `<span class="kv"><b>종류</b> ${esc(prev.kind)}</span>`,
1051	    bodyHtml: bodyHead + lossBanner(allLosses) + '<div class="sub-label">모델별 미리보기</div><div class="overlay-grid">' + perTool + '</div>',
1052	    footHtml: `<button class="btn btn-primary" data-store-apply="${esc(id)}">세 모델에 적용</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
1053	  });
1054	}
