1056	async function doStoreApply(id, resolution, newName, piAck) {
1057	  // registry 출처 항목은 서버가 PI 게이트에서 409 {piGate}를 줄 수 있다 → 기존 PI 모달 재사용.
1058	  // 재시도 컨텍스트(currentSync 패턴): ack 선택 시 같은 apply 요청에 piAck를 붙여 다시 보낸다.
1059	  currentStoreApply = { id, resolution, newName };
1060	  currentPullTool = null; currentAgentPull = null; currentSkillPull = null; currentSync = null;
1061	  const res = await fetch('/store/apply', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id, resolution, newName, piAck }) });
1062	  if (res.status === 409) { showPiModal(await res.json()); return; } // PI 게이트 흐름 보존
1063	  if (!res.ok) { currentStoreApply = null; toast('적용하지 못했습니다: ' + (await errMsg(res))); return; }
1064	  const r = await res.json();
1065	  $('#pi-modal').hidden = true;
1066	  currentStoreApply = null;
1067	  if (r.conflict) { openConflict({ type: 'store', id, kind: r.kind, name: r.name || r.id, diff: r.diff }); return; }
1068	  if (r.skipped) { toast(`건너뜀: ${r.kind} "${r.name || r.id}"`); }
1069	  else if (r.reason === 'excluded') { toast('제외됨 — 적용하지 않았습니다'); }
1070	  else if (r.applied) {
1071	    const lossN = (r.results || []).reduce((a, x) => a + ((x.losses || []).length), 0);
1072	    toast(`✓ 적용 완료 (3모델)${lossN ? ' · 손실 ' + lossN + '건' : ''}`);
1073	  }
1074	  if (loaded.skills) loadSkillOverview();
1075	  if (loaded.agents) loadAgentOverview();
1076	  if (loaded.store) loadStore($('#global-search-input').value);
1077	}
