1079	// ===================== 레지스트리 관리(스토어-R2) =====================
1080	async function openRegistriesModal() {
1081	  $('#registries-modal').hidden = false;
1082	  $('#registries-hint').textContent = '';
1083	  await renderRegistriesList();
1084	}
