1086	async function renderRegistriesList() {
1087	  $('#registries-body').innerHTML = '<div class="skel">불러오는 중…</div>';
1088	  let d;
1089	  try { d = await api('/registries'); }
1090	  catch { showLoadError('#registries-body', renderRegistriesList); return; }
1091	  lastRegistries = d.registries || [];
1092	  const rows = lastRegistries.map((r) => {
1093	    const upd = regUpdates[r.id];
1094	    const updBadge = upd
1095	      ? (upd.update_available
1096	        ? ' <span class="badge warn">업데이트 있음</span>'
1097	        : (upd.error ? ' <span class="badge muted">확인 불가</span>' : ' <span class="badge ok">최신</span>'))
1098	      : '';
1099	    // 기본(번들) 레지스트리: "기본" 배지 + 제거 버튼 숨김(사용자 것만 제거 가능). 새로고침은 노출.
1100	    const defBadge = r.official ? ' <span class="badge muted">기본</span>' : '';
1101	    const removeBtn = r.official ? '' : `<button class="btn btn-ghost btn-sm" data-reg-remove="${esc(r.id)}">제거</button>`;
1102	    return `<div class="proj-row">
1103	      <div class="proj-main">
1104	        <div class="proj-path">${esc(r.name || r.id)}${defBadge}${updBadge}</div>
1105	        <div class="proj-markers">${esc(r.url)} · rev ${esc(r.revision ? r.revision.slice(0, 7) : '–')} · 갱신 ${esc(r.last_refreshed || '–')}</div>
1106	      </div>
1107	      <span class="inline-acts">
1108	        <button class="btn btn-secondary btn-sm" data-reg-refresh="${esc(r.id)}">새로고침</button>
1109	        ${removeBtn}
1110	      </span>
1111	    </div>`;
1112	  }).join('') || '<div class="empty-state" style="padding:24px">등록된 레지스트리 없음.</div>';
1113	
1114	  $('#registries-body').innerHTML =
1115	    `<div class="proj-section">
1116	       <div class="sub-label">등록된 레지스트리</div>
1117	       ${rows}
1118	     </div>
1119	     <div class="proj-section">
1120	       <div class="sub-label">레지스트리 추가</div>
1121	       <div class="proj-add-row">
1122	         <input id="reg-add-url" class="pg-input" placeholder="git 저장소 URL (예: https://github.com/<owner>/<repo>)" />
1123	         <button class="btn btn-primary btn-sm" data-reg-add="1">추가</button>
1124	       </div>
1125	       <div class="muted" style="margin-top:8px;font-size:12px">추가는 등록만 합니다(통신 없음). 목록을 받아오려면 항목의 [새로고침]을 누르세요.</div>
1126	     </div>`;
1127	}
1128	
1129	async function regAdd() {
1130	  const url = ($('#reg-add-url') && $('#reg-add-url').value || '').trim();
1131	  if (!url) { $('#registries-hint').textContent = 'URL을 입력하세요.'; return; }
1132	  let r;
1133	  try { r = await api('/registries/add', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ url }) }); }
1134	  catch (e) { $('#registries-hint').textContent = e.message; return; }
1135	  if (r.error) { $('#registries-hint').textContent = r.error; return; }
1136	  $('#registries-hint').textContent = '';
1137	  if (r.added === false) toast(`이미 등록됨: ${r.id || ''}`);
1138	  else toast('레지스트리 등록됨 — [새로고침]으로 목록을 받아오세요');
1139	  await renderRegistriesList();
1140	}
1141	
1142	async function regRemove(id) {
1143	  let r;
1144	  try { r = await api('/registries/remove', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id }) }); }
1145	  catch (e) { toast('제거하지 못했습니다: ' + e.message); return; }
1146	  if (r && r.removed === false) {
1147	    // 기본(번들) 레지스트리는 제거 불가 — 명확히 안내만.
1148	    toast(r.reason === 'default' ? '기본 레지스트리는 제거할 수 없습니다' : '제거할 항목이 없습니다');
1149	    return;
1150	  }
1151	  delete regUpdates[id];
1152	  toast('레지스트리 제거됨');
1153	  await renderRegistriesList();
1154	  if (loaded.store) loadStore($('#global-search-input').value); // 캐시 항목 제거 반영
1155	}
1156	
1157	async function regRefresh(id) {
1158	  $('#registries-hint').textContent = '새로고침 중…';
1159	  const res = await fetch('/registries/refresh', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id }) });
1160	  const r = await res.json().catch(() => ({}));
1161	  $('#registries-hint').textContent = '';
1162	  // 새로고침 실패(네트워크 불가·repo 없음 등)는 일반 에러 토스트로 표시.
1163	  if (!res.ok || r.error) { toast('새로고침 실패: ' + (r.error || res.status)); return; }
1164	  toast(`✓ 레지스트리 갱신 — 스킬 ${r.count}개 (rev ${String(r.revision || '').slice(0, 7)})`);
1165	  await renderRegistriesList();
1166	  if (loaded.store) loadStore($('#global-search-input').value); // 병합 목록 재로드
1167	}
1168	
1169	async function regCheckUpdates() {
1170	  let results;
1171	  try { results = await api('/registries/updates'); }
1172	  catch (e) { toast('업데이트 확인 실패: ' + e.message); return; }
1173	  regUpdates = {};
1174	  let avail = 0, errs = 0;
1175	  for (const r of (Array.isArray(results) ? results : [])) {
1176	    regUpdates[r.id] = r;
1177	    if (r.error) errs++;
1178	    if (r.update_available) avail++;
1179	  }
1180	  // 결과(배지)는 레지스트리 모달 목록에 표시 — 닫혀 있으면 열어서 보여준다.
1181	  // 항목별 error는 목록의 "확인 불가" 배지로 표면화된다(기존 유지).
1182	  if ($('#registries-modal').hidden) await openRegistriesModal();
1183	  else await renderRegistriesList();
1184	  toast(avail ? `업데이트 ${avail}건 발견` : (errs ? `확인 실패 ${errs}건` : '모든 레지스트리가 최신입니다'));
1185	}
1186	
1187	// ===================== 충돌 모달(overwrite/skip/rename) =====================
1188	function openConflict(ctx) {
1189	  conflictCtx = ctx;
1190	  $('#conflict-msg').textContent = `${ctx.kind} "${ctx.name}" 가 이미 있습니다. 어떻게 할까요?`;
1191	  // #3: 기존 vs 새 내용 diff를 라디오 위에 렌더(차이가 확실히 보이게). diff가 없으면 우아하게 안내(#6).
1192	  const diffBox = $('#conflict-diff');
1193	  if (diffBox) {
1194	    if (ctx.diff && ctx.diff.length) {
1195	      diffBox.innerHTML = `<div class="sub-label">기존 내용 → 새 내용 (변경점)</div><div class="conflict-diff-scroll">${renderDiff(ctx.diff)}</div>`;
1196	    } else {
1197	      diffBox.innerHTML = '<div class="empty-state" style="padding:12px">차이를 불러올 수 없습니다.</div>';
1198	    }
1199	  }
1200	  // 라디오 초기화 → overwrite
1201	  $$('#conflict-options .radio-row').forEach((r, i) => r.classList.toggle('sel', i === 0));
1202	  $$('input[name=conflict-res]').forEach((r, i) => (r.checked = i === 0));
1203	  $('#conflict-newname').hidden = true;
1204	  $('#conflict-newname').value = '';
