// ===================== 지시문(instructions) =====================
async function loadInstructions() {
  showLoading('#instr-rows', 4);
  let ov;
  try { ov = await api('/overview'); }
  catch { showLoadError('#instr-rows', loadInstructions, 4); return; }
  $('#instr-status').textContent = ov.canonicalExists
    ? `중앙 저장소: 있음 (출처 ${ov.source})`
    : '중앙 저장소: 없음 — 모델에서 "가져오기"로 채우세요';
  setCount('instructions', (ov.items || []).length);

  const rows = $('#instr-rows');
  rows.innerHTML = (ov.items || []).map((it) => `
    <tr>
      <td><span class="item-name-cell"><span class="cell-tool-dot" style="background:${TOOL_COLOR[it.tool] || 'var(--st-muted)'}"></span><span class="item-name">${esc(it.tool)}</span></span></td>
      <td class="muted">${esc(it.name)}</td>
      <td>${it.exists ? '<span class="cell-pill ok">✓ 있음</span>' : '<span class="cell-pill muted">✗ 없음</span>'}</td>
      <td class="cell">
        <span class="inline-acts">
          <button class="btn btn-ghost btn-sm" data-pull="${esc(it.tool)}" ${it.exists ? '' : 'disabled'}>가져오기</button>
          <button class="btn btn-secondary btn-sm" data-diff="${esc(it.tool)}" ${ov.canonicalExists ? '' : 'disabled'}>미리보기</button>
        </span>
      </td>
    </tr>`).join('') || '<tr><td colspan="4" class="skel">항목 없음</td></tr>';
}

async function doPull(tool, piAck) {
  currentPullTool = tool; currentAgentPull = null; currentSkillPull = null; currentSync = null; currentStoreApply = null;
  const res = await fetch('/pull', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ from: tool, piAck }) });
  if (res.status === 409) { showPiModal(await res.json()); return; } // PI 게이트 흐름 보존
  if (!res.ok) { toast('적용하지 못했습니다: ' + (await errMsg(res))); return; }
  await res.json();
  $('#pi-modal').hidden = true;
  toast('가져오기 완료');
  loadInstructions();
}

// 쓰기 실패 응답(res)에서 서버 {error} 또는 상태코드를 읽어 이유 문자열로.
async function errMsg(res) {
  try { const b = await res.json(); return b.error || `오류 ${res.status}`; }
  catch { return `오류 ${res.status}`; }
}

function showPiModal(info) {
  $('#pi-detected').textContent = '감지: ' + (info.detected || []).join(', ');
  $('#pi-lines').textContent = (info.maskedLines || []).join('\n');
  $('#pi-modal').hidden = false;
}

async function doDiff(tool) {
  let d;
  try { d = await api('/diff?to=' + encodeURIComponent(tool)); }
  catch (e) { toast('미리보기를 불러오지 못했습니다: ' + e.message); return; }
  let body;
  if (!d.canonicalExists) body = '<div class="empty-state">중앙 저장소가 비어 있습니다. 먼저 가져오기 하세요.</div>';
  else if (!d.hasChanges) body = '<div class="empty-state">차이 없음 — 이미 동일</div>';
  else body = renderDiff(d.diff);
  openPanel({
    title: `${tool} 미리보기`,
    meta: `<span class="kv"><b>대상</b> ${esc(d.targetPath || '')}</span>`,
    bodyHtml: body,
    footHtml: d.canonicalExists ? `<button class="btn btn-primary" data-apply-instr="${esc(tool)}">적용 (백업 후 쓰기)</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>` : `<button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
  });
}

async function doApply(tool) {
  // #2: 미리보기 패널(doDiff)을 거친 적용이므로 native confirm() 제거 — 패널이 1차 게이트.
  try {
    const r = await api('/push', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ to: tool, apply: true }) });
    toast('적용 완료 · 백업: ' + (r.backupPath || '(신규)'));
    closePanel();
    loadInstructions();
    loadSyncLog();
  } catch (e) {
    toast('적용하지 못했습니다: ' + e.message); // 패널은 열린 채로 두어 재시도 가능
  }
}

