// ===================== 지시문(instructions) — 모델별 세로 카드 3개 (F3) =====================
// 데이터: GET /instr/matrix → { canonId, models:{claude|codex|gemini:{exists,group|null,readError?}}, groups, syncState }.
// "중앙 저장소"는 내부 백업일 뿐 — 화면에서 완전히 숨긴다(언급 금지).
// 상태별 카드 UI:
//   · synced(셋 다 동일)   → 모든 카드 "모두 동기화됨" 배지, 기준 버튼 비활성.
//   · drift/partial + 존재 → 상태 + [이 모델을 기준으로 동기화] 버튼.
//   · exists:false         → "파일 없음 — 기준 동기화 시 생성됩니다", 기준 버튼 비활성.
//   · readError            → "읽기 실패" + [다시 시도](재로드).

// 지시문 각 모델 파일명(간단 경로 표시용). 서버 render 대상 파일명과 동일.
const INSTR_FILE = { claude: 'CLAUDE.md', codex: 'AGENTS.md', gemini: 'GEMINI.md' };
// 종합 상태 → 상단 요약 배너 문구(단순 용어, D26-①). "drift"→"어긋남".
const INSTR_STATE = {
  synced:  { ko: '모두 동기화됨', badge: 'ok',    ic: '✅', desc: '세 모델의 지시문이 모두 같습니다.' },
  drift:   { ko: '어긋남',        badge: 'warn',  ic: '⚠', desc: '모델마다 지시문 내용이 다릅니다. 기준 모델을 골라 맞추세요.' },
  partial: { ko: '일부만 있음',   badge: 'warn',  ic: '⚠', desc: '일부 모델에만 지시문이 있습니다. 기준 모델로 나머지에 만들 수 있습니다.' },
  none:    { ko: '없음',          badge: 'muted', ic: '—', desc: '아직 어느 모델에도 지시문이 없습니다.' },
};
// 콘텐츠 그룹 번호 → 사람이 읽는 라벨("내용 A/B/…"). 같은 그룹 = 같은 내용.
function instrGroupLabel(group) {
  if (group == null) return '';
  return '내용 ' + String.fromCharCode(64 + (((group - 1) % 26) + 1)); // 1→A, 2→B …
}

async function loadInstructions() {
  showLoading('#instr-cards');
  $('#instr-summary').innerHTML = '';
  let m;
  try { m = await api('/instr/matrix'); }
  catch { showLoadError('#instr-cards', loadInstructions); return; }
  renderInstrMatrix(m);
}

function renderInstrMatrix(m) {
  const models = m.models || {};
  const state = INSTR_STATE[m.syncState] || INSTR_STATE.none;
  const present = TOOLS.filter((t) => models[t] && models[t].exists);
  // 카드 수 = 존재하는 지시문 항목 수(네비 카운트).
  setCount('instructions', present.length);

  // 상단 요약 배너(종합 상태).
  $('#instr-summary').innerHTML =
    `<div class="instr-summary-inner">
      <span class="badge ${state.badge}">${state.ic} ${esc(state.ko)}</span>
      <span class="instr-summary-desc">${esc(state.desc)}</span>
    </div>`;

  // 모델별 카드 3개.
  $('#instr-cards').innerHTML = TOOLS.map((tool) => instrCardHtml(tool, models[tool] || { exists: false, group: null }, m.syncState, present.length)).join('');
}

function instrCardHtml(tool, slot, syncState, presentCount) {
  const file = INSTR_FILE[tool] || '';
  const synced = syncState === 'synced';
  // 상태 줄 + 하단 동작(기준 버튼/다시 시도).
  let statusHtml, actionHtml;
  if (slot.readError) {
    // 읽기 실패 — 다시 시도(전체 재로드).
    statusHtml = `<span class="badge error">읽기 실패</span><span class="instr-note">파일을 읽지 못했습니다.</span>`;
    actionHtml = `<button class="btn btn-secondary btn-sm" data-instr-retry="1">다시 시도</button>`;
  } else if (!slot.exists) {
    // 파일 없음 — 기준 버튼 비활성.
    statusHtml = `<span class="badge muted">파일 없음</span><span class="instr-note">기준 동기화 시 생성됩니다.</span>`;
    actionHtml = `<button class="btn btn-secondary btn-sm" disabled>이 모델을 기준으로 동기화</button>`;
  } else if (synced) {
    // 셋 다 동일 — "모두 동기화됨" 배지 + 버튼 비활성.
    statusHtml = `<span class="badge ok">✅ 모두 동기화됨</span><span class="instr-tag ${syncGroupClass(slot.group)}">${esc(instrGroupLabel(slot.group))}</span>`;
    actionHtml = `<button class="btn btn-secondary btn-sm" disabled title="이미 세 모델이 동일합니다">이 모델을 기준으로 동기화</button>`;
  } else {
    // 존재 + 어긋남/일부있음 — 상태 + 기준 버튼(활성).
    statusHtml = `<span class="badge ok">✓ 있음</span><span class="instr-tag ${syncGroupClass(slot.group)}">${esc(instrGroupLabel(slot.group))}</span>`;
    actionHtml = `<button class="btn btn-primary btn-sm" data-instr-base="${esc(tool)}">이 모델을 기준으로 동기화</button>`;
  }
  return `<div class="instr-card ${slot.exists ? '' : 'absent'}">
    <div class="instr-card-head">
      <span class="tool-dot" style="background:${TOOL_COLOR[tool]}"></span>
      <span class="instr-card-name">${esc(tool)}</span>
    </div>
    <div class="instr-card-path" title="${esc(file)}">${esc(file)}</div>
    <div class="instr-card-status">${statusHtml}</div>
    <div class="instr-card-foot">${actionHtml}</div>
  </div>`;
}

// 쓰기 실패 응답(res)에서 서버 {error} 또는 상태코드를 읽어 이유 문자열로.
async function errMsg(res) {
  try { const b = await res.json(); return b.error || `오류 ${res.status}`; }
  catch { return `오류 ${res.status}`; }
}

function showPiModal(info) {
  $('#pi-detected').textContent = '감지: ' + (info.detected || []).join(', ');
  $('#pi-lines').textContent = (info.maskedLines || []).join('\n');
  $('#pi-modal').hidden = false;
}

// ── 지시문 동기화 흐름 (F3): [기준] 클릭 → 미리보기(apply:false) → 확인 1회 → apply:true ──
// 진행 중인 지시문 동기화 컨텍스트 {base} — PI 게이트(409) 재시도에 재사용.
let currentInstrSync = null;

// [이 모델을 기준으로 동기화] → apply:false 로 diff 요약을 받아 모달에 표시.
async function openInstrSync(base) {
  currentInstrSync = { base };
  currentPullTool = null; currentAgentPull = null; currentSkillPull = null; currentSync = null; currentStoreApply = null;
  $('#instr-sync-title').textContent = `${base} 기준으로 동기화`;
  $('#instr-sync-body').innerHTML = '<div class="skel">변경 요약을 계산하는 중…</div>';
  $('#instr-sync-confirm').disabled = true;
  $('#instr-sync-confirm').hidden = false;
  $('#instr-sync-cancel').textContent = '취소';
  $('#instr-sync-modal').hidden = false;
  let d;
  try { d = await api('/instr/sync', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ base, apply: false }) }); }
  catch (e) { $('#instr-sync-body').innerHTML = `<div class="empty-state">요약을 불러오지 못했습니다: ${esc(e.message)}</div>`; return; }
  renderInstrSyncPreview(d);
}

function renderInstrSyncPreview(d) {
  const targets = d.targets || [];
  const rows = targets.map((t) => {
    let detail;
    if (t.willCreate) detail = '<span class="badge ok">새로 생성</span>';
    else if (!t.hasChanges) detail = '<span class="badge muted">이미 같음 — 그대로</span>';
    else detail = `<span class="badge warn">바뀜</span><span class="instr-sync-nums">+${t.added} / -${t.removed}줄</span>`;
    return `<div class="sync-result-row">
      <span class="tool-dot" style="background:${TOOL_COLOR[t.to]}"></span>
      <span class="tool-name">${esc(t.to)}</span>
      ${detail}
    </div>`;
  }).join('');
  const anyChange = targets.some((t) => t.willCreate || t.hasChanges);
  const lead = anyChange
    ? `<b>${esc(d.base)}</b> 내용을 기준으로 다른 모델을 맞춥니다. 덮어쓰기 전에 자동 백업합니다.`
    : `다른 모델이 이미 <b>${esc(d.base)}</b>와 같습니다 — 바뀌는 파일이 없습니다.`;
  $('#instr-sync-body').innerHTML =
    `<div class="sync-lead">${lead}</div>
     <div class="sync-base-label">모델별 변경 요약</div>
     ${rows || '<div class="muted" style="padding:10px">맞출 대상 모델이 없습니다.</div>'}`;
  // 확인 버튼: 바뀔 게 없어도 실행은 허용(멱등 — 안전). 텍스트만 상황에 맞춘다.
  $('#instr-sync-confirm').disabled = false;
  $('#instr-sync-confirm').textContent = anyChange ? '이대로 동기화' : '동기화 실행';
}

// 확인 클릭 → apply:true. 409(PI)는 기존 PI 모달 패턴 재사용.
async function runInstrSync(piAck) {
  if (!currentInstrSync) return;
  const { base } = currentInstrSync;
  $('#instr-sync-confirm').disabled = true;
  const res = await fetch('/instr/sync', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ base, apply: true, piAck }) });
  // #9 패턴: 409 전에 버튼 복구(PI 취소 후 재실행 가능).
  if (res.status === 409) { $('#instr-sync-confirm').disabled = false; showPiModal(await res.json()); return; }
  if (!res.ok) { $('#instr-sync-confirm').disabled = false; toast('동기화하지 못했습니다: ' + (await errMsg(res))); return; }
  const r = await res.json();
  $('#pi-modal').hidden = true;
  // PI 게이트에서 제외 선택 → 기준을 저장하지 않아 동기화 중단.
  if (r.pulled && r.pulled.imported === false) {
    $('#instr-sync-confirm').disabled = false;
    toast('제외됨 — 동기화하지 않았습니다');
    return;
  }
  const results = r.results || [];
  const okN = results.filter((x) => x.applied).length;
  const failN = results.filter((x) => x.applied === false).length;
  const backups = results.filter((x) => x.applied && x.backupPath).length;
  toast(`✓ 동기화 완료 · ${okN}개 모델${failN ? ` · 실패 ${failN}` : ''}${backups ? ` · 백업 ${backups}건` : ''}`);
  closeInstrSyncModal();
  loadInstructions();
  loadSyncLog();
}

function closeInstrSyncModal() {
  $('#instr-sync-modal').hidden = true;
  currentInstrSync = null;
}

