async function loadUsage() {
  showLoading('#usage-rows', 5);
  let u;
  try { u = await api('/usage'); }
  catch { showLoadError('#usage-rows', loadUsage, 5); return; }
  // F6: 최근 활동순(최신이 위). 서버는 오래된 순(LRU)으로 주므로 lastActivity 내림차순으로 재정렬.
  // 시각이 없는 항목은 맨 아래로. (정렬만 — 서버·core는 건드리지 않는다.)
  const items = (u.items || []).slice().sort((a, b) => {
    const ta = a.lastActivity ? new Date(a.lastActivity).getTime() : 0;
    const tb = b.lastActivity ? new Date(b.lastActivity).getTime() : 0;
    return tb - ta;
  });
  // F6: 고정(pin)·보관(archive) 버튼/배지 제거 — 관찰 데이터만 보여준다(동작 열 삭제).
  $('#usage-rows').innerHTML = items.length ? items.map((x) => {
    const last = formatDateHuman(x.lastActivity);
    return `<tr>
      <td><span class="item-name">${esc(x.id)}</span></td>
      <td class="muted">${esc(x.kind)}</td>
      <td><span class="cell-pill ${x.state === 'stale' ? 'warn' : 'ok'}">${esc(stateKo(x.state))}</span></td>
      <td>${esc(String(x.telemetry.churn_count))}</td>
      <td class="muted" title="${esc(x.lastActivity || '')}">${esc(last)}</td>
    </tr>`;
  }).join('') : `<tr><td colspan="5" class="skel">항목 없음 — 먼저 가져오기 하세요
    <span class="inline-acts" style="justify-content:center;margin-top:10px"><button class="btn btn-secondary btn-sm" data-goto="skills">스킬 보기</button></span></td></tr>`;
}

