+/* 다크모드 제거 — 라이트 고정. (이전 다크 테마 오버라이드 블록 전부 삭제) */
+/* 반응형 3단 레이아웃:
+   · ≥1024px(넓음): 세로 사이드바 + 본문. 사이드바 접기 지원(.sidebar-collapsed).
+   · <1024px(중간/좁음): 사이드바 숨김 + 상단 가로 메뉴(.topnav).            */
+  grid-template-rows: 1fr;
+  grid-template-areas: "sidebar main";
+.app.sidebar-collapsed { grid-template-columns: var(--sidebar-w-collapsed) 1fr; }
+.sidebar { grid-area: sidebar; }
+.main { grid-area: main; }
+/* 상단 가로 메뉴는 넓은 화면에선 숨김(사이드바 사용). */
+.topnav { display: none; }
+  min-width: 0; overflow: hidden;
+.brand-titles { min-width: 0; }
+/* 사이드바 접기 버튼(브랜드 우측). 접힘/펼침 동일 버튼. */
+.sidebar-toggle {
+  margin-left: auto; flex: none;
+  width: 26px; height: 26px; border-radius: 7px;
+  display: grid; place-items: center; font-size: 15px; line-height: 1;
+  color: var(--st-muted); border: 1px solid var(--color-hairline); background: var(--color-canvas);
+  transition: background var(--duration-fast), transform var(--duration-fast) var(--ease-standard);
+}
+.sidebar-toggle:hover { background: var(--color-canvas-parchment); }
+
+/* ----- 접힌 사이드바(아이콘만) ----- */
