+.app.sidebar-collapsed .nav-label,
+.app.sidebar-collapsed .nav-group-label,
+.app.sidebar-collapsed .nav-count,
+.app.sidebar-collapsed .sidebar-foot .nav-label { display: none; }
+.app.sidebar-collapsed .sidebar { padding: 22px 10px 18px; align-items: center; }
+.app.sidebar-collapsed .brand { padding: 4px 0 20px; justify-content: center; }
+.app.sidebar-collapsed .sidebar-toggle { margin-left: 0; transform: rotate(180deg); }
+.app.sidebar-collapsed .nav-item { justify-content: center; padding: 9px 0; width: 42px; }
+.app.sidebar-collapsed .server-row,
+.app.sidebar-collapsed .local-badge { justify-content: center; }
